function setMessage(t,e,i=""){t&&(t.textContent=e,t.classList.remove("error","success"),i&&t.classList.add(i))}function clearElementChildren(t){for(;t.firstChild;)t.removeChild(t.firstChild)}function availabilityClass(t){return t<=0?"out":t<=2?"low":"available"}function prettyDate(t){return new Date(t).toLocaleString()}
